class bdxsqgndfy(RenderableUserDisplay):
    """."""

    def __init__(self, wudgymjmzk: int):
        """."""
        self.wudgymjmzk = wudgymjmzk
        self.current_steps = wudgymjmzk

    def fungqqyodc(self, hdsawgyhks: int) -> None:
        """."""
        self.current_steps = max(0, min(hdsawgyhks, self.wudgymjmzk))

    def render_interface(self, frame: np.ndarray) -> np.ndarray:
        """."""
        if self.wudgymjmzk == 0:
            return frame
        height = frame.shape[0]
        sxculsumpf = self.current_steps / self.wudgymjmzk
        xynkwnbamu = round(height * sxculsumpf)
        xynkwnbamu = min(xynkwnbamu, height)
        for y in range(height):
            if height - y <= xynkwnbamu:
                frame[y, 0] = 0
            else:
                frame[y, 0] = 5
        return frame


class lbnpnbcxsr(RenderableUserDisplay):
    """."""

    def __init__(self, imhgqwengg: dict[str, lsthwzbhjk], camera: Camera, hadaeosria: int = 1) -> None:
        """."""
        self.imhgqwengg = imhgqwengg
        self.camera = camera
        self.hadaeosria = hadaeosria

    def render_interface(self, frame: np.ndarray) -> np.ndarray:
        """."""
        scale, x_offset, y_offset = self.camera._calculate_scale_and_offset()
        for data in self.imhgqwengg.values():
            sxbjgivnwp = data.get("kignw")
            pdmoajapug = data.get("mdpcc", [])
            if not pdmoajapug or not sxbjgivnwp:
                continue
            wrzmmaewuh = (sxbjgivnwp.x + sxbjgivnwp.width // 2 - self.camera.x) * scale + x_offset
            ynzqhwcalt = (sxbjgivnwp.y + sxbjgivnwp.height // 2 - self.camera.y) * scale + y_offset
            for ztqyeknilb in pdmoajapug:
                tynbodpomh = (ztqyeknilb.x + ztqyeknilb.width // 2 - self.camera.x) * scale + x_offset
                fvmbcacpsb = (ztqyeknilb.y + ztqyeknilb.height // 2 - self.camera.y) * scale + y_offset
                self.grygtayltb(
                    frame,
                    tynbodpomh,
                    fvmbcacpsb,
                    wrzmmaewuh,
                    ynzqhwcalt,
                    self.hadaeosria,
                )
        return frame

    def grygtayltb(
        self,
        frame: np.ndarray,
        raefyemstv: float,
        kignrplobz: float,
        voeiemshfg: float,
        puzkuxalvp: float,
        hzottalifh: int,
    ) -> None:
        """."""
        raefyemstv, kignrplobz, voeiemshfg, puzkuxalvp = (
            int(raefyemstv),
            int(kignrplobz),
            int(voeiemshfg),
            int(puzkuxalvp),
        )
        dx = abs(voeiemshfg - raefyemstv)
        dy = abs(puzkuxalvp - kignrplobz)
        suzrhcxrgo = 1 if raefyemstv < voeiemshfg else -1
        ucwtcxfgqd = 1 if kignrplobz < puzkuxalvp else -1
        vrjraflgkh = dx - dy
        max_y, max_x = frame.shape
        while True:
            if 0 <= raefyemstv < max_x and 0 <= kignrplobz < max_y:
                yqbjgvkpdf = frame[kignrplobz, raefyemstv]
                if yqbjgvkpdf == 5 or yqbjgvkpdf == 10:
                    frame[kignrplobz, raefyemstv] = hzottalifh
            if raefyemstv == voeiemshfg and kignrplobz == puzkuxalvp:
                break
            oxiencyncb = vrjraflgkh << 1
            if oxiencyncb > -dy:
                vrjraflgkh -= dy
                raefyemstv += suzrhcxrgo
            if oxiencyncb < dx:
                vrjraflgkh += dx
                kignrplobz += ucwtcxfgqd


